import{_ as a,o as n,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Homebrew Formula","description":"Creating a Homebrew formula and tap for easy macOS installation, including SHA256 verification, dependency declarations, and automated formula updates.","frontmatter":{"title":"Homebrew Formula","description":"Creating a Homebrew formula and tap for easy macOS installation, including SHA256 verification, dependency declarations, and automated formula updates."},"headers":[],"relativePath":"learn/project/15-production-polish/07-homebrew-formula.md","filePath":"learn/project/15-production-polish/07-homebrew-formula.md"}'),e={name:"learn/project/15-production-polish/07-homebrew-formula.md"};function t(p,s,r,c,i,y){return n(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="homebrew-formula" tabindex="-1">Homebrew Formula <a class="header-anchor" href="#homebrew-formula" aria-label="Permalink to &quot;Homebrew Formula&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to write a Homebrew formula that downloads and installs the agent binary</li><li>How to set up a Homebrew tap repository for distributing the formula</li><li>Techniques for automating formula updates when new versions are released</li></ul></blockquote><p>For macOS users, <code>brew install</code> is the expected way to install developer tools. If your agent is not on Homebrew, many potential users will not bother installing it. Setting up a Homebrew tap and formula is simpler than it looks, and once it is in place, new releases can update the formula automatically through your CI pipeline.</p><h2 id="homebrew-concepts" tabindex="-1">Homebrew Concepts <a class="header-anchor" href="#homebrew-concepts" aria-label="Permalink to &quot;Homebrew Concepts&quot;">​</a></h2><p>Before writing the formula, let&#39;s clarify a few Homebrew terms:</p><ul><li><strong>Formula</strong> -- a Ruby script that tells Homebrew how to download, build (if needed), and install your software.</li><li><strong>Tap</strong> -- a Git repository of formulas. Your tap is separate from Homebrew&#39;s core repository, which means you do not need to go through the Homebrew review process.</li><li><strong>Bottle</strong> -- a pre-built binary package. For binary-only distributions (which is our case), the formula simply downloads the binary.</li><li><strong>Cask</strong> -- used for macOS GUI applications. CLI tools use formulas, not casks.</li></ul><h2 id="creating-a-homebrew-tap-repository" tabindex="-1">Creating a Homebrew Tap Repository <a class="header-anchor" href="#creating-a-homebrew-tap-repository" aria-label="Permalink to &quot;Creating a Homebrew Tap Repository&quot;">​</a></h2><p>A tap is a GitHub repository with a specific naming convention: <code>homebrew-&lt;name&gt;</code>. For the agent:</p><ol><li>Create a repository named <code>homebrew-agent</code> under your GitHub account.</li><li>Inside it, create a <code>Formula</code> directory.</li><li>Place your formula Ruby file in <code>Formula/agent.rb</code>.</li></ol><p>Users will install from your tap with:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> tap</span><span style="color:#A6E3A1;"> yourusername/agent</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> yourusername/agent/agent</span></span></code></pre></div><h2 id="writing-the-formula" tabindex="-1">Writing the Formula <a class="header-anchor" href="#writing-the-formula" aria-label="Permalink to &quot;Writing the Formula&quot;">​</a></h2><p>Here is a complete formula that downloads pre-built binaries for Intel and Apple Silicon Macs:</p><div class="language-ruby"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Formula/agent.rb</span></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#FAB387;"> Agent</span><span style="color:#94E2D5;"> &lt;</span><span style="color:#FAB387;"> Formula</span></span>
<span class="line"><span style="color:#CDD6F4;">  desc </span><span style="color:#A6E3A1;">&quot;A CLI coding agent powered by LLMs&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  homepage </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  version </span><span style="color:#A6E3A1;">&quot;0.1.0&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  license </span><span style="color:#A6E3A1;">&quot;MIT&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">  on_macos </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#F9E2AF;font-style:italic;"> Hardware</span><span style="color:#9399B2;">::</span><span style="color:#F9E2AF;font-style:italic;">CPU</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">arm?</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent/releases/download/v</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">version</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/agent-aarch64-apple-darwin.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;abc123...replace_with_actual_sha256_for_arm64...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    else</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent/releases/download/v</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">version</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/agent-x86_64-apple-darwin.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;def456...replace_with_actual_sha256_for_x86_64...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    end</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">  on_linux </span><span style="color:#CBA6F7;">do</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#F9E2AF;font-style:italic;"> Hardware</span><span style="color:#9399B2;">::</span><span style="color:#F9E2AF;font-style:italic;">CPU</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">arm?</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent/releases/download/v</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">version</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/agent-aarch64-unknown-linux-musl.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;789abc...replace_with_actual_sha256_for_linux_arm64...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    else</span></span>
<span class="line"><span style="color:#CDD6F4;">      url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent/releases/download/v</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">version</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/agent-x86_64-unknown-linux-musl.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">      sha256 </span><span style="color:#A6E3A1;">&quot;012def...replace_with_actual_sha256_for_linux_x86_64...&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    end</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">  def</span><span style="color:#89B4FA;font-style:italic;"> install</span></span>
<span class="line"><span style="color:#CDD6F4;">    bin</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;agent&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">  test</span><span style="color:#CBA6F7;"> do</span></span>
<span class="line"><span style="color:#CDD6F4;">    assert_match version</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">to_s</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> shell_output</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">bin</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/agent --version&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"><span style="color:#CBA6F7;">end</span></span></code></pre></div><p>The formula does the following:</p><ol><li>Detects the platform and architecture.</li><li>Downloads the correct pre-built binary from your GitHub release.</li><li>Verifies the SHA256 checksum (critical for security).</li><li>Installs the binary into Homebrew&#39;s <code>bin</code> directory.</li><li>Provides a test that verifies the binary outputs the correct version.</li></ol><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you have published Python packages, you know that <code>pip install</code> handles everything. Homebrew is macOS&#39;s equivalent system-level package manager. The Ruby formula is roughly analogous to a <code>setup.py</code> or <code>pyproject.toml</code> -- it declares metadata, download URLs, and installation steps. The key difference is that Homebrew formulas download <em>pre-built binaries</em> rather than building from source (unless you set up a source formula), so you must produce and host the binaries yourself.</p></div><h2 id="generating-sha256-checksums" tabindex="-1">Generating SHA256 Checksums <a class="header-anchor" href="#generating-sha256-checksums" aria-label="Permalink to &quot;Generating SHA256 Checksums&quot;">​</a></h2><p>The SHA256 checksums are essential -- they verify that the downloaded binary has not been tampered with. You generate them from your release artifacts:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Generate checksums for all release archives</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">shasum</span><span style="color:#A6E3A1;"> -a</span><span style="color:#FAB387;"> 256</span><span style="color:#A6E3A1;"> agent-</span><span style="color:#CDD6F4;">*</span><span style="color:#A6E3A1;">.tar.gz</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Or using openssl</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">openssl</span><span style="color:#A6E3A1;"> dgst</span><span style="color:#A6E3A1;"> -sha256</span><span style="color:#A6E3A1;"> agent-aarch64-apple-darwin.tar.gz</span></span></code></pre></div><p>In your release automation (covered in the next subchapter), you will generate these automatically and use them to update the formula.</p><h2 id="building-a-source-formula" tabindex="-1">Building a Source Formula <a class="header-anchor" href="#building-a-source-formula" aria-label="Permalink to &quot;Building a Source Formula&quot;">​</a></h2><p>If you prefer to let Homebrew build from source (which avoids hosting binaries but requires users to have Rust installed), the formula looks different:</p><div class="language-ruby"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#FAB387;"> Agent</span><span style="color:#94E2D5;"> &lt;</span><span style="color:#FAB387;"> Formula</span></span>
<span class="line"><span style="color:#CDD6F4;">  desc </span><span style="color:#A6E3A1;">&quot;A CLI coding agent powered by LLMs&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  homepage </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  url </span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent/archive/refs/tags/v0.1.0.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  sha256 </span><span style="color:#A6E3A1;">&quot;source_tarball_sha256_here...&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">  license </span><span style="color:#A6E3A1;">&quot;MIT&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">  depends_on </span><span style="color:#A6E3A1;">&quot;rust&quot;</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> :</span><span style="color:#F38BA8;">build</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">  def</span><span style="color:#89B4FA;font-style:italic;"> install</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    system</span><span style="color:#A6E3A1;"> &quot;cargo&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;install&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> *</span><span style="color:#CDD6F4;">std_cargo_args</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">  test</span><span style="color:#CBA6F7;"> do</span></span>
<span class="line"><span style="color:#CDD6F4;">    assert_match version</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">to_s</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> shell_output</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">#{</span><span style="color:#CDD6F4;">bin</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">/agent --version&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">  end</span></span>
<span class="line"><span style="color:#CBA6F7;">end</span></span></code></pre></div><p>The <code>std_cargo_args</code> method is a Homebrew helper that passes <code>--root=#{prefix}</code> and other standard Cargo installation flags. The <code>depends_on &quot;rust&quot; =&gt; :build</code> declaration ensures Rust is installed before building.</p><p>For a binary distribution, the pre-built binary formula is preferred because it avoids the 5-10 minute compile time.</p><h2 id="installing-shell-completions" tabindex="-1">Installing Shell Completions <a class="header-anchor" href="#installing-shell-completions" aria-label="Permalink to &quot;Installing Shell Completions&quot;">​</a></h2><p>You can include shell completions in the formula installation:</p><div class="language-ruby"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> install</span></span>
<span class="line"><span style="color:#CDD6F4;">  bin</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">install</span><span style="color:#A6E3A1;"> &quot;agent&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">  # Generate and install shell completions</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">  generate_completions_from_executable</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">bin</span><span style="color:#94E2D5;">/</span><span style="color:#A6E3A1;">&quot;agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;completions&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">  # Or install pre-generated completion files</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">  # bash_completion.install &quot;completions/agent.bash&quot; =&gt; &quot;agent&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">  # zsh_completion.install &quot;completions/_agent&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">  # fish_completion.install &quot;completions/agent.fish&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">end</span></span></code></pre></div><p>The <code>generate_completions_from_executable</code> helper runs your binary with the completions subcommand and places the output in the correct locations. This is why the <code>agent completions &lt;shell&gt;</code> command you built in the CLI subchapter matters -- Homebrew can call it directly.</p><h2 id="automating-formula-updates" tabindex="-1">Automating Formula Updates <a class="header-anchor" href="#automating-formula-updates" aria-label="Permalink to &quot;Automating Formula Updates&quot;">​</a></h2><p>When you release a new version, the formula needs to be updated with the new version number, download URLs, and checksums. Here is a script that automates this:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;font-style:italic;">#!/bin/bash</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># scripts/update-homebrew.sh</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">set</span><span style="color:#A6E3A1;"> -euo</span><span style="color:#A6E3A1;"> pipefail</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">VERSION</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#EBA0AC;font-style:italic;">$1</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">TAP_REPO</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;yourusername/homebrew-agent&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Download the release archives and compute checksums</span></span>
<span class="line"><span style="color:#CBA6F7;">declare</span><span style="color:#A6E3A1;"> -A</span><span style="color:#CDD6F4;"> CHECKSUMS</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> target </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;aarch64-apple-darwin&quot;</span><span style="color:#CDD6F4;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;x86_64-apple-darwin&quot;</span><span style="color:#CDD6F4;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;aarch64-unknown-linux-musl&quot;</span><span style="color:#CDD6F4;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;x86_64-unknown-linux-musl&quot;</span><span style="color:#9399B2;">;</span><span style="color:#CBA6F7;"> do</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">    archive</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;agent-</span><span style="color:#CDD6F4;">\${target}</span><span style="color:#A6E3A1;">.tar.gz&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    url</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;https://github.com/yourusername/agent/releases/download/v</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">/</span><span style="color:#CDD6F4;">\${archive}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Downloading </span><span style="color:#CDD6F4;">\${archive}</span><span style="color:#A6E3A1;">...&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    curl</span><span style="color:#A6E3A1;"> -sLO</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$url</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    CHECKSUMS</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">$target</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">$(</span><span style="color:#89B4FA;font-style:italic;">shasum</span><span style="color:#A6E3A1;"> -a</span><span style="color:#FAB387;"> 256</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$archive</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> awk</span><span style="color:#A6E3A1;"> &#39;{print $1}&#39;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    rm</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$archive</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">done</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Clone the tap repository and update the formula</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> clone</span><span style="color:#A6E3A1;"> &quot;https://github.com/</span><span style="color:#CDD6F4;">\${TAP_REPO}</span><span style="color:#A6E3A1;">.git&quot;</span><span style="color:#A6E3A1;"> homebrew-tap</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> homebrew-tap</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Use sed to update version and checksums in the formula</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">sed</span><span style="color:#A6E3A1;"> -i</span><span style="color:#A6E3A1;"> &#39;&#39;</span><span style="color:#A6E3A1;"> &quot;s/version </span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">.*</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">/version </span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">/&quot;</span><span style="color:#A6E3A1;"> Formula/agent.rb</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Updated formula to version </span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Checksums:&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> target </span><span style="color:#CBA6F7;">in</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${</span><span style="color:#94E2D5;">!</span><span style="color:#CDD6F4;">CHECKSUMS</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">@</span><span style="color:#9399B2;">]</span><span style="color:#CDD6F4;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">;</span><span style="color:#CBA6F7;"> do</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;  </span><span style="color:#CDD6F4;">\${target}</span><span style="color:#A6E3A1;">: </span><span style="color:#CDD6F4;">\${CHECKSUMS</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">$target</span><span style="color:#9399B2;">]</span><span style="color:#CDD6F4;">}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">done</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># The CI pipeline would commit and push these changes</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> Formula/agent.rb</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> commit</span><span style="color:#A6E3A1;"> -m</span><span style="color:#A6E3A1;"> &quot;Update agent to </span><span style="color:#CDD6F4;">\${VERSION}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> push</span><span style="color:#A6E3A1;"> origin</span><span style="color:#A6E3A1;"> main</span></span></code></pre></div><p>In the next subchapter on release automation, you will integrate this into your GitHub Actions workflow so that pushing a version tag automatically updates the Homebrew formula.</p><h2 id="testing-the-formula-locally" tabindex="-1">Testing the Formula Locally <a class="header-anchor" href="#testing-the-formula-locally" aria-label="Permalink to &quot;Testing the Formula Locally&quot;">​</a></h2><p>Before publishing, test the formula locally:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install from the local formula file</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> --formula</span><span style="color:#A6E3A1;"> ./Formula/agent.rb</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Test it</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> test</span><span style="color:#A6E3A1;"> agent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Audit the formula for style issues</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> audit</span><span style="color:#A6E3A1;"> --strict</span><span style="color:#A6E3A1;"> --formula</span><span style="color:#A6E3A1;"> ./Formula/agent.rb</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Uninstall when done testing</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">brew</span><span style="color:#A6E3A1;"> uninstall</span><span style="color:#A6E3A1;"> agent</span></span></code></pre></div><p>The <code>brew audit --strict</code> command checks for common formula issues like missing descriptions, incorrect license formats, or missing test blocks.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code is distributed through npm rather than Homebrew, leveraging the Node.js ecosystem&#39;s cross-platform package management. Many Rust CLI tools (like <code>ripgrep</code>, <code>bat</code>, and <code>fd</code>) maintain Homebrew formulas in the official homebrew-core repository, which requires a formal review process but reaches a much larger audience. Starting with your own tap is the right first step -- you can submit to homebrew-core later once the tool is mature and has enough users.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Set up a GitHub repository named <code>homebrew-&lt;name&gt;</code> as your Homebrew tap, with a <code>Formula</code> directory containing the Ruby formula file -- users install with <code>brew tap</code> + <code>brew install</code>.</li><li>Write platform-aware formulas using <code>on_macos</code>/<code>on_linux</code> and <code>Hardware::CPU.arm?</code> blocks to download the correct pre-built binary for each user&#39;s system.</li><li>Always include SHA256 checksums in the formula for security verification, and regenerate them automatically when releasing new versions.</li><li>Include a <code>test</code> block in the formula that validates the installed binary (at minimum, check that <code>--version</code> output matches the formula version).</li><li>Automate formula updates in your CI pipeline so that pushing a version tag triggers a new release, generates checksums, and updates the tap repository without manual intervention.</li></ul>`,41)])])}const h=a(e,[["render",t]]);export{d as __pageData,h as default};
